let queueControl = {};

function createEvent() {
    node.warn("Updating Ical Server Status Dashboard");
    queueControl.controlledByEventFromIcalNbr = controlledByEventFromIcalNbr;
    queueControl.startTimeUpdateSchedule = Date.now();
    queueControl.roomCounter = 0;
    flow.set('sf_queueControl', queueControl);

    for (let j = 0; j < rooms.length; j++) {
        if (rooms[j].control === "controlledByEventFromIcal") {
            node.send({
                action: "queue",
                payload: rooms[j]
            });
        }
    }
}

let controlledByEventFromIcalNbr = rooms.filter(element => element.control === "controlledByEventFromIcal").length;
let interval = context.get('icalServerUpdate');


if (!interval) {
    createEvent();
    interval = setInterval(createEvent, 60 * 60 * 1000);
    context.set('icalServerUpdate', interval);
}

let queueControl = flow.get('sf_queueControl');

queueControl.roomCounter++;

if(queueControl.roomCounter % queueControl.controlledByEventFromIcalNbr == 0){
    //node.warn(`${queueControl.controlledByEventFromIcalNbr} URL processed in ${(Date.now() - queueControl.startTimeUpdateSchedule) / 1000} s`);
}

msg.action = "unqueue";
return msg;

let roomsQueue = flow.get('f_roomsQueue');
const maxQueueSize = 50;


////////////////// Queue ////////////////
if (msg.action === "queue") {
    if (roomsQueue.length >= maxQueueSize) {
        node.error(`Room queue has exeeded its maximum size ${maxQueueSize}`);
        return null;
    }
    else if (roomsQueue.length == 0 && flow.get('f_initialStart')) {
        // First message, no need to queue.
        flow.set('f_initialStart', false);
        //node.warn("Testing ical server for each URL...");
        return {
            "url": msg.payload.url,
            "timezone": msg.payload.timeZone,
            "preview": msg.payload.nbrDaysPreview,
            "roomConf": msg.payload,
            "status": { fill: "green", shape: "dot", text: `Room queue size : ${roomsQueue.length}` }
        }
    }
    else {
        //node.warn("Other message, Queue");
        roomsQueue.push(msg.payload);
        flow.set('f_roomsQueue', roomsQueue);
    }
}

////////////////// Unqueue ////////////////
else if (msg.action === "unqueue") {
    if (roomsQueue.length === 0) {
        flow.set('f_initialStart', true);
        //node.warn("Unqueue with lenght == 0, initialStart = true");
    }
    else {
        let newRoom = roomsQueue.shift();
        flow.set('f_roomsQueue', roomsQueue);
        //node.warn("Unqueue");
        return {
            "url": newRoom.url,
            "timezone": newRoom.timeZone,
            "preview": msg.payload.nbrDaysPreview,
            "roomConf": newRoom,
            "status": { fill: "green", shape: "dot", text: `Room queue size : ${roomsQueue.length}` }
        }
    }
}

