let icalToScheduleConf = global.get('g_icalToScheduleConf');

let roomConf = msg.roomConf;
let eventNumber = msg.total;
let events = [/* {eventStart : Date , eventEnd : Date,, ...}*/];  // List of events to create.
let httpRequestEventList = {};

///////////////////////////////////////////////////////////////////////
/////////////////     Events manipulation  ////////////////////////////
///////////////////////////////////////////////////////////////////////

function eventCreation() {
  for (let i = 0; i < eventNumber; i++) {
    // Event are discarded according to their "event description" in the ics file.
    if (!icalToScheduleConf.eventsToDiscard.some(discardStr => msg.payload[i].description?.includes(discardStr))) {

      //////////  groupEvents == true   //////////////
      if (icalToScheduleConf.groupEvents) {
        let msgEventStart = new Date(msg.payload[i].eventStart);
        let msgEventEnd = new Date(msg.payload[i].eventEnd);

        // Check if an event with same Year-Month-Date already exists in events[].
        const idx = events.findIndex(evt => {
          return (
            msgEventStart.getDate() === evt.eventStart.getDate() &&
            msgEventStart.getMonth() === evt.eventStart.getMonth() &&
            msgEventStart.getFullYear() === evt.eventStart.getFullYear()
          );
        });

        if (idx != -1) {    // Event with same Year-Month-Date already exists, we merge.
          if (msgEventStart < events[idx].eventStart) events[idx].eventStart = msgEventStart; // Update start time?
          if (msgEventEnd > events[idx].eventEnd) events[idx].eventEnd = msgEventEnd;         // Update end time?
        }
        else {              // Event with same Year-Month-Date already doesn't exist, we add a new one.
          //node.warn("Event added");
          events.push(msg.payload[i]);
          events.at(-1).eventStart = new Date(events.at(-1).eventStart);  // at(-1) = last index
          events.at(-1).eventEnd = new Date(events.at(-1).eventEnd);      // at(-1) = last index
          events.at(-1).summary = "Merged Events";
          //node.warn(events);
        }
      }

      //////////  groupEvents == false   //////////////
      else { // In that cas, we add a new one anyway.
        //node.warn("Event added");
        events.push(msg.payload[i]);
        events.at(-1).eventStart = new Date(events.at(-1).eventStart);  // at(-1) = last index
        events.at(-1).eventEnd = new Date(events.at(-1).eventEnd);      // at(-1) = last index
      }
    }
    else {
      //node.warn(`Event ${i} : ${msg.payload[i].summary} is discarded`);
    }
  }

  // node.warn(events);


  ///////////////////////////////////////////////////////////////////////
  /////////////////    HTTP Request Creation   //////////////////////////
  ///////////////////////////////////////////////////////////////////////
  let eventID = 1;

  for (let i = 0; i < events.length; i++) {

    let start = new Date(events[i].eventStart);
    let end = new Date(events[i].eventEnd);

    // Rule 1 : discard events shorter than 30 minutes
    const durationMinutes = (end.getTime() - start.getTime()) / (1000 * 60);
    if (durationMinutes < icalToScheduleConf.minimumSlotDuration) {
      node.warn(`Event ${i} "${events[i].summary}" discarded (duration < ${icalToScheduleConf.minimumSlotDuration} min).`);
      continue;
    }

    // Adjust the time with timeOffsetBeforeStart and timeOffsetBeforeEnd
    if (icalToScheduleConf.groupEvents) {
      const midnight = new Date(start);
      midnight.setHours(0, 0, 0, 0);

      start.setMinutes(start.getMinutes() - roomConf.timeOffsetBeforeStart);
      end.setMinutes(end.getMinutes() - roomConf.timeOffsetBeforeEnd);

      // Rule 2 : Clamp start to midnight if it went before 00:00
      if (start < midnight) {
        start = new Date(midnight);
        node.warn(`Event ${i} "${events[i].summary}" clamp to midnight.`);
      }

      // Rule 3 : ensure start < end.
      if (start >= end) {
        node.warn(`Event ${i} "${events[i].summary}" discarded  (start >= end).`);
        continue;
      }
    }


    // Create Event request
    let eventObject = {
      [eventID]: {
        "event-priority": 16,
        period: {
          date: {
            month: start.getMonth() + 1,
            year: start.getFullYear(),
            "day-of-month": start.getDate()
          },
          type: "Date"
        },
        name: events[i].summary,
        transitions: {
          1: {
            time: start.toLocaleTimeString("fr-FR", { timeZone: icalToScheduleConf.timeZone }),
            value: roomConf.tempOccupied,
            key: "1"
          },
          2: {
            time: end.toLocaleTimeString("fr-FR", { timeZone: icalToScheduleConf.timeZone }),
            value: null,
            key: "2"
          }
        },
        key: String(eventID)
      }
    };
    eventID++;
    httpRequestEventList = { ...httpRequestEventList, ...eventObject };   // Merge with the previous object
  }

  let request = {
    "method": "POST",
    "url": `https://${icalToScheduleConf.controllerIPAddress}/api/rest/v2/services/bacnet/local/objects/schedules/${roomConf.scheduleID}`,
    "headers": { Authorization: icalToScheduleConf.httpAuthentication, "Content-Type": "application/json" },
    "payload": {
      "special-events": httpRequestEventList,
      "weekly-schedule" :  roomConf.weekly  ,
      "object-name": roomConf.scheduleName,
      "schedule-default": roomConf.tempUnoccupied
