                valveSetpoint?.["present-value"] !== undefined &&
                controllerSetpoint?.["present-value"] !== undefined &&
                valveSetpoint["present-value"] === controllerSetpoint["present-value"];


            room.valves[name] = {
                "valveTemperature": valveTemperature ? valveTemperature["present-value"] : undefined,
                "valveSetpoint": valveSetpoint ? valveSetpoint["present-value"] : undefined,
                "controllerSetpoint": controllerSetpoint ? controllerSetpoint["present-value"] : undefined,
                "valvePosition": valvePosition ? valvePosition["present-value"] : undefined,
                "status": status
            }
        });
    });
});



rooms.forEach(room => {

    /**************Average temperature **************/
    let temperatures = [];

    Object.values(room.valves).forEach(valve => {
        if (valve.valveTemperature !== null && valve.valveTemperature !== undefined) {
            temperatures.push(valve.valveTemperature);
        }
    });

    let count = temperatures.length;

    if (count === 0) {
        room.averageTemperature = undefined;
    }
    else if (count < 3) {
        let sum = 0;
        temperatures.forEach(t => sum += t);
        room.averageTemperature = sum / count;
    }
    else {
        temperatures.sort((a, b) => a - b);
        temperatures.shift();
        temperatures.pop();

        let sum = 0;
        temperatures.forEach(t => sum += t);
        room.averageTemperature = sum / temperatures.length;
    }

    /************** Temperature Gap between setpoint and average Temp **************/
    if (
        room.averageTemperature !== null &&
        room.averageTemperature !== undefined &&
        room.ADEsetpoint !== null &&
        room.ADEsetpoint !== undefined
    ) {
        room.temperatureGap = room.averageTemperature - room.ADEsetpoint;
    } else {
        room.temperatureGap = undefined;
    }

    /************** Room occupency **************/
    /*** Room is occupied at leat one valveSetpoint has temperature "tempOccupied" *****/

    let valveSetpoints = new Set();
    Object.values(room.valves).forEach(valve => {
        if (valve.valveSetpoint !== null && valve.valveSetpoint !== undefined) {
            valveSetpoints.add(valve.valveSetpoint);
        }
    })

    if (valveSetpoints.size) {
        room.occupency = valveSetpoints.has(room.tempOccupied);
    }
    else {
        room.occupency = undefined;
    }

});

return msg;

